'use strict';

const $=(s,r=document)=>r.querySelector(s), $$=(s,r=document)=>[...r.querySelectorAll(s)];
const esc=v=>String(v??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
const money=v=>Number(v||0).toLocaleString('pt-BR',{style:'currency',currency:'BRL'});
const date=v=>v?new Date(v).toLocaleDateString('pt-BR'):'—';
const dt=v=>v?new Date(v).toLocaleString('pt-BR'):'—';
const PAYMENT_LABELS={'dia-15':'Dia 15','dia-30':'Dia 30 ou último dia do mês',avista:'À vista',pix:'PIX',credito:'Crédito',debito:'Débito'};
const paymentDueDate=(term,base=new Date())=>{if(!['dia-15','dia-30'].includes(term))return'';const now=new Date(base),make=(year,month)=>{const last=new Date(year,month+1,0).getDate(),day=term==='dia-15'?15:Math.min(30,last);return new Date(year,month,day,12)};let due=make(now.getFullYear(),now.getMonth());if(due<new Date(now.getFullYear(),now.getMonth(),now.getDate(),0))due=make(now.getFullYear(),now.getMonth()+1);return due.toISOString().slice(0,10)};
const paymentInfo=(term,base,dueDate)=>{if(term==='dia-05')term='dia-15';const label=PAYMENT_LABELS[term]||PAYMENT_LABELS['dia-15'];if(!['dia-15','dia-30'].includes(term))return{label,detail:'Pagamento no ato da conclusão da OS',due:'Imediato'};const due=dueDate||paymentDueDate(term,base);return{label,detail:`Vencimento: ${date(due+'T12:00:00')}`,due:date(due+'T12:00:00')}};
const avatarContent=user=>user?.avatar?`<img src="${user.avatar}" alt="Avatar de ${esc(user.name)}">`:esc(user?.name?.[0]||'?');
const state={token:localStorage.getItem('gl_token')||'',user:null,view:'dashboard',params:{},cache:{},menu:false,vehiclePhotos:[]};
let deferredInstallPrompt=null;
window.addEventListener('beforeinstallprompt',event=>{event.preventDefault();deferredInstallPrompt=event;document.documentElement.classList.add('can-install')});
window.addEventListener('appinstalled',()=>{deferredInstallPrompt=null;document.documentElement.classList.remove('can-install');toast('Aplicativo instalado com sucesso.')});

const NAV=[['dashboard','⌂','Dashboard'],['orders','▣','Ordens de Serviço'],['vehicles','▤','Veículos'],['clients','♙','Clientes'],['agenda','□','Agenda'],['stock','◇','Estoque'],['finance','＄','Financeiro'],['warranties','♢','Garantias'],['reports','▥','Relatórios'],['sharing','⇄','Compartilhamentos'],['settings','⚙','Configurações']];
const BOTTOM=[['dashboard','⌂','Início'],['orders','▣','OS'],['vehicles','▤','Veículos'],['agenda','□','Agenda'],['more','•••','Mais']];
const COLORS=['green','yellow','blue','orange','red','purple','gray'];
const CHECKLIST={
  eletrica:{name:'Elétrica / Eletrônica',groups:[
    ['Sistema de partida e carga',['Tensão da bateria em repouso','Carga do alternador com motor ligado','Bornes e terminais','Motor de partida','Correia do alternador','Aterramento do chassi']],
    ['Chicote e conectores',['Inspeção visual do chicote','Conectores multivias','Fusíveis e relés']],
    ['Painel e instrumentos',['Painel de instrumentos','Códigos de falha (scanner OBD/J1939)','Sensores de rotação, temperatura e pressão']],
    ['Iluminação e sinalização',['Faróis','Lanternas','Setas','Luz de freio','Luz de ré','Luz de placa e teto','Pisca-alerta']],
    ['Sistemas auxiliares',['Ar-condicionado elétrico','Vidros, travas e alarme','Tacógrafo','Conector elétrico do reboque','Bateria auxiliar']]
  ]},
  mecanica:{name:'Mecânica',groups:[
    ['Motor',['Nível e condição do óleo','Vazamentos','Filtro de ar','Filtro de óleo','Filtro de combustível','Separador de água','Correias e tensores','Turbina','Sistema de arrefecimento']],
    ['Freios',['Lonas ou pastilhas','Tambor ou disco','Sistema pneumático','Regulador de folga','Freio de estacionamento']],
    ['Suspensão e direção',['Molas ou suspensão pneumática','Amortecedores','Buchas e pinos','Caixa de direção','Terminais e barra','Rolamento de roda']],
    ['Transmissão e diferencial',['Óleo do câmbio','Óleo do diferencial','Embreagem','Cardan e cruzetas','Retentores']],
    ['Rodas e pneus',['Pressão dos pneus','Desgaste dos pneus','Torque das rodas','Alinhamento e balanceamento']],
    ['Chassi e estrutura',['Trincas no chassi','Quinta roda ou engate','Tanque e suportes']]
  ]}
};

async function api(path,opts={}){
  const headers={'Content-Type':'application/json',...(opts.headers||{})};if(state.token)headers.Authorization=`Bearer ${state.token}`;
  const res=await fetch('/api/'+path,{...opts,headers});const data=await res.json().catch(()=>({}));
  if(res.status===401&&path!=='login'){logout(false);throw new Error('Sua sessão expirou.');}
  if(!res.ok)throw new Error(data.error||'Não foi possível concluir a operação.');return data;
}
function toast(msg){const el=$('#toast');el.textContent=msg;el.classList.add('show');setTimeout(()=>el.classList.remove('show'),2800)}
function modal(html){$('#modalCard').innerHTML=html;$('#modal').classList.add('open');$('#modal').setAttribute('aria-hidden','false');setTimeout(bind,0)}
function closeModal(){$('#modal').classList.remove('open');$('#modal').setAttribute('aria-hidden','true')}
function go(view,params={}){state.view=view;state.params=params;state.menu=false;history.pushState({view,params},'',`#${view}${params.id?'/'+params.id:''}`);render()}
function activeNav(id){return state.view===id||(id==='orders'&&state.view.startsWith('order'))||(id==='vehicles'&&state.view.startsWith('vehicle'))}

function loginView(){return `<div class="login-page"><section class="login-hero"></section><section class="login-side"><div class="login-card"><img class="login-logo" src="/images/logo.png" alt="GL Electromechanic"><h1>Bem-vindo de volta!</h1><p class="muted">Acesse sua conta para continuar</p><form id="loginForm"><div class="field"><label>Usuário ou e-mail</label><div class="input-icon"><span>♙</span><input name="username" autocomplete="username" placeholder="Digite seu usuário ou e-mail" required></div></div><div class="field"><label>Senha</label><div class="input-icon"><span>♙</span><input name="password" type="password" autocomplete="current-password" placeholder="Digite sua senha" required></div></div><div class="login-options"><label class="check"><input type="checkbox" checked> Lembrar de mim</label><span class="link">Esqueci minha senha</span></div><button class="btn btn-primary btn-block">→ &nbsp; Entrar no sistema</button></form><div class="login-divider"><span>ou</span></div><button class="btn btn-block biometric-btn" data-action="biometric-login"><span class="fingerprint">◉</span> Entrar com biometria</button><div class="login-note"><span>🛡 <b>Sistema seguro e protegido</b><small>Todos os dados são criptografados</small></span><span>Versão 1.0.0</span></div></div></section></div>`}

function shell(content){return `<div class="shell ${state.menu?'menu-open':''}"><aside class="sidebar"><div class="brand"><img src="/images/logo.jpg" alt="GL Electromechanic"></div><nav class="nav">${NAV.map(n=>`<button class="nav-btn ${activeNav(n[0])?'active':''}" data-go="${n[0]}"><span class="nav-icon">${n[1]}</span>${n[2]}</button>`).join('')}</nav><div class="sidebar-user"><div class="avatar">${esc(state.user.name[0])}</div><div><b>${esc(state.user.name)}</b><small>${state.user.role==='admin'?'Administrador':'Técnico'}</small></div><button class="round" data-action="logout" title="Sair">↪</button></div></aside><main class="main"><header class="topbar"><button class="menu-toggle" data-action="menu">☰</button><div class="page-name">${pageTitle()}</div><input class="search global-search" id="globalSearch" placeholder="Buscar veículo, OS, cliente..."><div class="top-actions"><button class="round btn-primary" data-action="quick">＋</button><button class="round">♧</button><div class="avatar">${esc(state.user.name[0])}</div></div></header><div class="content">${content}</div></main><nav class="bottom-nav">${BOTTOM.map(n=>`<button class="bottom-btn ${activeNav(n[0])?'active':''}" data-go="${n[0]}"><span>${n[1]}</span>${n[2]}</button>`).join('')}</nav></div>`}
function pageTitle(){return ({dashboard:'Dashboard',orders:'Ordens de Serviço','order-new':'Nova Ordem de Serviço','order-detail':'Detalhes da OS',vehicles:'Veículos','vehicle-form':state.params.id?'Editar Veículo':'Cadastro de Veículo',clients:'Clientes',agenda:'Agenda',stock:'Estoque',finance:'Financeiro',warranties:'Garantias',reports:'Relatórios',sharing:'Compartilhamentos',settings:'Configurações',more:'Menu'})[state.view]||'N.A.Diesel Diagnósticos e Programação'}

async function render(){
  const app=$('#app');if(!state.token||!state.user){app.innerHTML=loginView();bind();return}
  app.innerHTML=shell('<div class="empty">Carregando…</div>');bind();
  try{let html='';switch(state.view){case'dashboard':html=await dashboard();break;case'vehicles':html=await vehicles();break;case'vehicle-form':html=await enhancedVehicleForm();break;case'orders':html=await orders();break;case'order-new':html=await orderNew();break;case'order-detail':html=await orderDetail();break;case'clients':html=await clientsView();break;case'agenda':html=await agenda();break;case'stock':html=await stockView();break;case'finance':html=await financeView();break;case'sharing':html=await sharing();break;case'settings':html=await settings();break;case'more':html=more();break;default:html=generic(state.view)}app.innerHTML=shell(html);bind();}catch(e){app.innerHTML=shell(`<div class="panel empty">${esc(e.message)}</div>`);bind();toast(e.message)}
}

async function dashboard(){const d=await api('dashboard');state.cache=d;const stats=[['🚚',d.stats.vehicles,'Caminhões cadastrados','12%'],['📦',d.stats.waiting,'Aguardando peças','8%'],['🔧',d.stats.open,'Em manutenção','5%'],['⚡',d.stats.electrical,'Elétrica','3%'],['⚙',d.stats.mechanical,'Mecânica','7%'],['✓',d.stats.finished,'Finalizados hoje','20%'],['▰',d.stats.delivered,'Entregues hoje','15%']];return `<div class="page-head"><div><h1>Dashboard</h1><p>Visão geral da oficina</p></div><div class="actions"><button class="btn btn-primary" data-go="order-new">＋ Nova OS</button></div></div><section class="grid stats">${stats.map((s,i)=>`<article class="stat"><div class="stat-top"><div class="stat-icon" style="color:${['#32d15e','#ffd21b','#42aaf5','#ff811d','#ef4444','#ae72ff','#ddd'][i]}">${s[0]}</div><div><strong>${s[1]}</strong><div class="stat-label">${s[2]}</div></div></div><div class="delta">↗ ${s[3]} <span class="muted">vs ontem</span></div></article>`).join('')}</section><section class="grid dash-grid"><article class="panel"><div class="panel-head"><h2>Ordens de Serviço em andamento</h2><span class="link" data-go="orders">Ver todas →</span></div>${ordersTable(d.orders.slice(0,6),d.vehicles)}</article><article class="panel"><div class="panel-head"><h2>Indicadores da oficina</h2><span class="muted">Este mês</span></div><div class="chart">${[25,42,38,58,65,61,78,73,88,96,92,100].map((h,i)=>`<div class="bar" style="height:${h}%" data-value="${money(h*2850)}"></div>`).join('')}</div></article><article class="panel"><div class="panel-head"><h2>Agenda</h2><span class="link" data-go="agenda">Ver agenda →</span></div><div class="list">${d.agenda.length?d.agenda.slice(0,6).map(a=>`<div class="list-row"><div><b>${esc(a.title)}</b><div class="muted">${dt(a.start)}</div></div><span class="status">Agendado</span></div>`).join(''):'<div class="empty">Nenhum compromisso agendado.</div>'}</div></article></section><section class="grid dash-lower"><article class="panel"><div class="panel-head"><h3>Caminhões aguardando peças</h3></div>${simpleOrderList(d.orders.filter(o=>o.status==='Aguardando peça'),d.vehicles)}</article><article class="panel"><div class="panel-head"><h3>Alertas importantes</h3></div><div class="list"><div class="list-row"><span>⚠ Checklists com itens críticos</span><b class="yellow">Verificar</b></div><div class="list-row"><span>◈ Estoque abaixo do mínimo</span><b class="yellow">Ver estoque</b></div><div class="list-row"><span>♢ Garantias próximas do vencimento</span><b class="yellow">Ver garantias</b></div></div></article><article class="panel"><div class="panel-head"><h3>Assistente da oficina</h3><span class="status yellow">NOVO</span></div><div class="panel-body"><p>Olá, ${esc(state.user.name)}! 👋</p><p class="muted">Hoje há <b>${d.stats.open}</b> OS abertas e <b>${d.stats.waiting}</b> aguardando peças.</p><button class="btn btn-primary" data-go="orders">Revisar ordens</button></div></article></section>`}
function ordersTable(list,vehicles){if(!list.length)return'<div class="empty">Nenhuma ordem cadastrada.</div>';return `<div class="table-wrap"><table><thead><tr><th>OS</th><th>Veículo</th><th>Serviço</th><th>Status</th><th>Previsão</th></tr></thead><tbody>${list.map(o=>{const v=vehicles.find(v=>v.id===o.vehicleId)||{};return`<tr data-open-os="${o.id}"><td>#${o.number}</td><td>${esc(v.brand||'')} ${esc(v.model||'')}</td><td>${esc(o.problem||'—')}</td><td>${status(o.status)}</td><td>${date(o.dueDate)}</td></tr>`}).join('')}</tbody></table></div>`}
function simpleOrderList(list,vehicles){return list.length?`<div class="list">${list.slice(0,5).map(o=>{const v=vehicles.find(v=>v.id===o.vehicleId)||{};return`<div class="list-row"><span>#${o.number} · ${esc(v.brand||'Veículo')} ${esc(v.model||'')}</span><b class="yellow">${date(o.createdAt)}</b></div>`}).join('')}</div>`:'<div class="empty">Nenhum registro.</div>'}
function status(s){const c=s==='Finalizada'||s==='Entregue'?'green':s==='Aguardando peça'?'yellow':s==='Elétrica'?'orange':'blue';return`<span class="status ${c}">${esc(s||'Aberta')}</span>`}

async function vehicles(){const list=await api('vehicles');state.cache.vehicles=list;return `<div class="page-head"><div><h1>Veículos</h1><p>Frota cadastrada na oficina</p></div><button class="btn btn-primary" data-go="vehicle-form">＋ Novo veículo</button></div><div class="panel"><div class="panel-head"><h2>${list.length} veículo(s)</h2><input class="search" id="vehicleSearch" placeholder="Placa, marca, modelo..."></div>${list.length?`<div class="table-wrap"><table><thead><tr><th>Foto</th><th>Placa</th><th>Veículo</th><th>Proprietário</th><th>Quilometragem</th><th>Status</th></tr></thead><tbody>${list.map(v=>`<tr data-open-vehicle="${v.id}"><td>${v.photos?.[0]?`<img class="vehicle-thumb" src="${v.photos[0]}" alt="">`:'<div class="vehicle-thumb placeholder">▣</div>'}</td><td><b>${esc(v.plate)}</b></td><td>${esc(v.brand)} ${esc(v.model)}</td><td>${esc(v.ownerName||v.company||'—')}</td><td>${esc(v.mileage||'0')} km</td><td>${v.active?'<span class="status green">Ativo</span>':'<span class="status gray">Inativo</span>'}</td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">Nenhum veículo cadastrado. Cadastre o primeiro veículo para começar.</div>'}</div>`}

async function vehicleForm(){let v={active:true,photos:[]};if(state.params.id)v=await api('vehicles/'+state.params.id);state.vehiclePhotos=[...(v.photos||[])];return `<div class="page-head"><div><h1>${v.id?'Editar':'Cadastro de'} Veículo</h1><p>Preencha as informações do veículo</p></div><div class="actions"><button class="btn" data-go="vehicles">← Voltar</button><button class="btn btn-primary" data-action="save-vehicle">Salvar veículo</button></div></div><form id="vehicleForm" class="form-layout"><section class="panel form-main"><div class="tabs"><div class="tab active">Dados Gerais</div><div class="tab">Informações Técnicas</div><div class="tab">Componentes</div><div class="tab">Observações</div><div class="tab">Documentos</div></div><h3 class="section-title">Dados do Veículo</h3><div class="form-grid">${field('plate','Placa *',v.plate,true)}${field('renavam','Renavam',v.renavam)}${select('type','Tipo *',['Cavalo Mecânico','Caminhão Toco','Caminhão Truck','Ônibus','Van','Outro'],v.type)}${select('category','Categoria',['Particular','Frota','Terceiro'],v.category)}${field('brand','Marca *',v.brand,true)}${field('model','Modelo *',v.model,true)}${field('year','Ano Fabricação *',v.year,'number')}${field('modelYear','Ano Modelo',v.modelYear,'number')}${field('color','Cor',v.color)}${select('fuel','Combustível',['Diesel','Elétrico','Híbrido','Outro'],v.fuel)}${field('mileage','Quilometragem',v.mileage,'number')}${field('hours','Horímetro',v.hours,'number')}${field('chassis','Chassi (VIN) *',v.chassis,true)}${field('engine','Motor',v.engine)}${field('doors','Portas',v.doors,'number')}${select('traction','Capacidade de Tração',['4x2','6x2','6x4','8x2','8x4'],v.traction)}</div><h3 class="section-title">Informações do Proprietário</h3><div class="form-grid">${field('company','Cliente / Empresa *',v.company,true,'text','span-2')}${field('document','CNPJ / CPF',v.document)}${field('contact','Contato',v.contact)}${field('phone','Telefone',v.phone)}${field('email','E-mail',v.email,'email')}${field('city','Cidade',v.city)}${field('state','Estado',v.state)}</div><h3 class="section-title">Informações Adicionais</h3><div class="field"><label>Observações gerais</label><textarea name="notes" rows="4">${esc(v.notes||'')}</textarea></div><label class="switch"><input type="checkbox" name="active" ${v.active!==false?'checked':''}> Veículo ativo — disponível para novas OS</label><input type="hidden" name="id" value="${esc(v.id||'')}"></section><aside class="side-stack"><section class="panel panel-pad"><h3>Fotos do Veículo</h3><div id="photoPreview">${photoPreview()}</div><label class="photo-add" style="margin-top:8px;aspect-ratio:auto;padding:13px">＋ Adicionar fotos<input id="photoInput" type="file" accept="image/*" multiple hidden></label><small class="muted">Até 8 imagens. O veículo permanecerá sem foto se nenhuma for adicionada.</small></section><section class="panel panel-pad"><h3>Resumo do Veículo</h3>${summary('Placa',v.plate)}${summary('Chassi',v.chassis)}${summary('Motor',v.engine)}${summary('Quilometragem',v.mileage?`${v.mileage} km`:'—')}</section><section class="panel panel-pad"><h3>Histórico de OS</h3><div class="muted">O histórico aparecerá após salvar e vincular ordens de serviço.</div></section></aside></form>`}
function field(name,label,value='',type='text',required=false,cls=''){if(type===true){required=true;type='text'}return`<div class="field ${cls}"><label>${label}</label><input name="${name}" type="${type}" value="${esc(value)}" ${required?'required':''}></div>`}
function select(name,label,options,value=''){return`<div class="field"><label>${label}</label><select name="${name}"><option value="">Selecione</option>${options.map(o=>`<option ${o===value?'selected':''}>${o}</option>`).join('')}</select></div>`}
function summary(k,v){return`<div class="summary-row"><span class="muted">${k}</span><b>${esc(v||'—')}</b></div>`}
function photoPreview(){return state.vehiclePhotos.length?`<img class="photo-main" src="${state.vehiclePhotos[0]}" alt="Foto principal"><div class="photo-grid">${state.vehiclePhotos.map((p,i)=>`<div style="position:relative"><img class="photo-item" src="${p}" alt="Foto ${i+1}"><button type="button" class="close" data-remove-photo="${i}" style="position:absolute;right:2px;top:2px;background:#000a;border-radius:50%">×</button></div>`).join('')}</div>`:'<div class="photo-main placeholder">📷<br><small>Sem fotos</small></div>'}

async function orders(){const [list,vehicles]=await Promise.all([api('orders'),api('vehicles')]);state.cache.orders=list;state.cache.vehicles=vehicles;return `<div class="page-head"><div><h1>Ordens de Serviço</h1><p>Acompanhamento dos serviços da oficina</p></div><button class="btn btn-primary" data-go="order-new">＋ Nova OS</button></div><div class="panel"><div class="panel-head"><h2>${list.length} ordem(ns)</h2></div>${ordersTable(list,vehicles)}</div>`}
async function orderNew(){const vehicles=await api('vehicles');return `<div class="page-head"><div><h1>Nova Ordem de Serviço</h1><p>Abra uma nova ordem para um veículo</p></div><button class="btn" data-go="orders">← Voltar</button></div><form id="orderForm" class="panel panel-pad"><div class="form-grid"><div class="field span-2"><label>Veículo *</label><select name="vehicleId" required><option value="">Selecione</option>${vehicles.map(v=>`<option value="${v.id}">${esc(v.plate)} — ${esc(v.brand)} ${esc(v.model)}</option>`).join('')}</select></div>${select('priority','Prioridade',['Baixa','Média','Alta'],'Média')}${select('category','Categoria',['Elétrica','Mecânica','Diagnóstico','Preventiva'],'')}${field('dueDate','Previsão de entrega','','datetime-local')}${field('mechanic','Mecânico responsável',state.user.name)}<div class="field span-2 payment-field"><label>Prazo / forma de pagamento *</label><select name="paymentTerms" required><option value="dia-15">Dia 15</option><option value="dia-30">Dia 30 ou último dia do mês</option><option value="avista">À vista</option><option value="pix">PIX</option><option value="credito">Crédito</option><option value="debito">Débito</option></select></div><div class="field span-all"><label>Problema relatado *</label><textarea name="problem" rows="4" required></textarea></div></div><div class="actions" style="justify-content:flex-end"><button class="btn btn-primary">Abrir OS</button></div></form>`}
async function orderDetail(){const [o,vehicles]=await Promise.all([api('orders/'+state.params.id),api('vehicles')]);const v=vehicles.find(v=>v.id===o.vehicleId)||{};const tab=state.params.tab||'services';return `<div class="page-head"><div><h1>OS #${o.number} ${status(o.status)}</h1><p>Aberta em ${dt(o.createdAt)}</p></div><div class="actions"><button class="btn" onclick="print()">▣ Imprimir OS</button><button class="btn btn-primary" data-action="finalize-os">Finalizar OS</button></div></div><section class="panel os-head-card"><div class="os-block"><div class="vehicle-mini">${v.photos?.[0]?`<img class="vehicle-thumb" style="width:145px;height:105px" src="${v.photos[0]}">`:'<div class="vehicle-thumb placeholder" style="width:145px;height:105px">🚚</div>'}<div><h2>${esc(v.brand||'Veículo')} ${esc(v.model||'')}</h2><p>${esc(v.company||'')}</p><p class="muted">Placa: ${esc(v.plate||'—')} · Km: ${esc(v.mileage||'—')}</p><p class="muted">Chassi: ${esc(v.chassis||'—')}</p></div></div></div><div class="os-block"><p class="muted">Responsável</p><h3>${esc(o.mechanic||'Não definido')}</h3><p>${esc(v.contact||'')}</p><p>${esc(v.phone||'')}</p></div><div class="os-block">${summary('Previsão',dt(o.dueDate))}${summary('Prioridade',o.priority)}${summary('Categoria',o.category)}${summary('Status',o.status)}</div></section><div class="tabs" style="margin-top:15px">${[['services','Serviços e Peças'],['checklist','Checklist'],['diagnosis','Diagnóstico'],['history','Histórico'],['photos','Fotos / Vídeos'],['documents','Documentos']].map(t=>`<div class="tab ${tab===t[0]?'active':''}" data-os-tab="${t[0]}">${t[1]}</div>`).join('')}</div>${tab==='checklist'?checklistView(o):tab==='history'?historyView(o):tab==='diagnosis'?diagnosisView(o):tab==='photos'?photosView(v):tab==='documents'?genericPanel('Documentos da OS','Nenhum documento anexado.') : servicesView(o)}`}
function servicesView(o){const st=(o.services||[]).reduce((a,x)=>a+Number(x.value||0),0),pt=(o.parts||[]).reduce((a,x)=>a+Number(x.qty||0)*Number(x.value||0),0);return`<div class="os-detail-grid"><div><section class="panel"><div class="panel-head"><h3>Serviços</h3><button class="btn" data-action="add-service">＋ Adicionar serviço</button></div>${itemsTable(o.services,'service')}</section><section class="panel" style="margin-top:12px"><div class="panel-head"><h3>Peças</h3><button class="btn" data-action="add-part">＋ Adicionar peça</button></div>${itemsTable(o.parts,'part')}</section></div><aside class="side-stack"><section class="panel panel-pad"><h3>Resumo financeiro</h3>${summary('Total de serviços',money(st))}${summary('Total de peças',money(pt))}<div class="summary-row"><b>TOTAL GERAL</b><span class="money-total">${money(st+pt)}</span></div></section><section class="panel panel-pad"><h3>Situação atual</h3>${(o.timeline||[]).map(x=>`<div class="list-row"><span>● ${esc(x.label)}</span><small>${dt(x.at)}</small></div>`).join('')}</section></aside></div>`}
function itemsTable(items,type){if(!items?.length)return'<div class="empty">Nenhum item adicionado.</div>';return`<div class="table-wrap"><table><thead><tr><th>Descrição</th><th>${type==='service'?'Mecânico':'Quantidade'}</th><th>Valor</th><th></th></tr></thead><tbody>${items.map((x,i)=>`<tr><td>${esc(x.description)}</td><td>${esc(type==='service'?x.mechanic:x.qty)}</td><td>${money(type==='service'?x.value:Number(x.qty)*Number(x.value))}</td><td><button class="close" data-remove-item="${type}:${i}">×</button></td></tr>`).join('')}</tbody></table></div>`}
function checklistView(o){const cat=state.params.category||'eletrica';return`<div class="tabs"><div class="tab ${cat==='eletrica'?'active':''}" data-check-cat="eletrica">⚡ Elétrica / Eletrônica</div><div class="tab ${cat==='mecanica'?'active':''}" data-check-cat="mecanica">⚙ Mecânica</div></div><div class="check-groups">${CHECKLIST[cat].groups.map((g,gi)=>`<section class="check-group"><div class="check-title">${g[0]}</div>${g[1].map((item,ii)=>{const key=`${cat}_${gi}_${ii}`,val=o.checklist?.[key]?.state||'';return`<div class="check-item"><span>${item}</span><div class="states">${[['ok','OK'],['atencao','!'],['critico','✕'],['nao_aplicavel','N/A']].map(s=>`<button class="state ${val===s[0]?'on':''}" data-state="${s[0]}" data-check-key="${key}" title="${s[0]}">${s[1]}</button>`).join('')}</div></div>`}).join('')}</section>`).join('')}</div>`}
function historyView(o){return`<div class="panel"><div class="panel-head"><h3>Histórico da OS</h3></div><div class="list">${(o.timeline||[]).map(x=>`<div class="list-row"><div><b>${esc(x.label)}</b><div class="muted">${esc(x.user||'Sistema')}</div></div><span>${dt(x.at)}</span></div>`).join('')}</div></div>`}
function diagnosisView(o){return`<section class="panel panel-pad"><h3>Diagnóstico</h3><div class="field"><label>Laudo e observações técnicas</label><textarea id="diagnosisText" rows="10">${esc(o.diagnosis||o.problem||'')}</textarea></div><button class="btn btn-primary" data-action="save-diagnosis">Salvar diagnóstico</button></section>`}
function photosView(v){return`<section class="panel panel-pad"><h3>Fotos do veículo vinculado</h3>${v.photos?.length?`<div class="photo-grid" style="grid-template-columns:repeat(auto-fill,minmax(160px,1fr))">${v.photos.map(p=>`<img class="photo-item" src="${p}">`).join('')}</div>`:'<div class="empty">Este veículo ainda não possui fotos.</div>'}</section>`}

async function agenda(){const events=await api('agenda');return`<div class="page-head"><div><h1>Agenda</h1><p>Programação da oficina — sem divisão por boxes</p></div><button class="btn btn-primary" data-action="new-event">＋ Novo compromisso</button></div><div class="panel"><div class="panel-head"><h2>${new Date().toLocaleDateString('pt-BR',{dateStyle:'full'})}</h2></div><div class="table-wrap"><div class="agenda-grid"><div class="agenda-cell"></div>${['Segunda','Terça','Quarta','Quinta'].map(d=>`<div class="agenda-cell"><b>${d}</b></div>`).join('')}${Array.from({length:11},(_,i)=>{const h=i+7;return`<div class="agenda-cell agenda-time">${String(h).padStart(2,'0')}:00</div>${[0,1,2,3].map(day=>{const ev=events.find(e=>new Date(e.start).getHours()===h&&new Date(e.start).getDay()===day+1);return`<div class="agenda-cell">${ev?`<div class="agenda-event"><b>${esc(ev.title)}</b><br>${esc(ev.description||'')}</div>`:''}</div>`}).join('')}`}).join('')}</div></div></div>`}
async function sharing(){const [shares,users]=await Promise.all([api('shares'),api('users')]);const incoming=shares.filter(s=>s.recipientId===state.user.id),outgoing=shares.filter(s=>s.ownerId===state.user.id);return`<div class="page-head"><div><h1>Compartilhamentos</h1><p>Controle quem pode visualizar ou editar suas informações</p></div><button class="btn btn-primary" data-action="new-share">＋ Compartilhar</button></div><div class="grid sharing-grid"><section class="panel"><div class="panel-head"><h2>Solicitações recebidas</h2></div>${incoming.length?incoming.map(s=>`<div class="share-card"><b>${esc(s.owner?.name)}</b> quer compartilhar <b>${shareLabel(s)}</b><p class="muted">Permissão: ${s.permission==='edit'?'visualizar e editar':'somente visualizar'}</p>${s.status==='pending'?`<button class="btn btn-primary" data-share-response="${s.id}:approved">Aprovar</button> <button class="btn" data-share-response="${s.id}:rejected">Recusar</button>`:status(s.status==='approved'?'Aprovado':'Recusado')}</div>`).join(''):'<div class="empty">Nenhuma solicitação recebida.</div>'}</section><section class="panel"><div class="panel-head"><h2>Informações que compartilhei</h2></div>${outgoing.length?outgoing.map(s=>`<div class="share-card"><b>${shareLabel(s)}</b> com ${esc(s.recipient?.name)}<p class="muted">${s.permission==='edit'?'Pode editar':'Somente leitura'} · ${s.status}</p><button class="btn btn-danger" data-revoke-share="${s.id}">Revogar</button></div>`).join(''):'<div class="empty">Você ainda não compartilhou informações.</div>'}</section></div><script type="application/json" id="usersData">${JSON.stringify(users).replace(/</g,'\\u003c')}</script>`}
function resourceName(r){return({vehicles:'Veículos',orders:'Ordens de Serviço',agenda:'Agenda'})[r]||r}
function shareLabel(s){return s.resource==='orders'&&s.orderNumber?`OS #${s.orderNumber}`:resourceName(s.resource)}
async function settings(){const audit=await api('audit');return`<div class="page-head"><div><h1>Configurações</h1><p>N.A.Diesel Diagnósticos e Programação</p></div></div><div class="grid sharing-grid"><section class="panel panel-pad"><h3>Perfil do usuário</h3><div class="profile-editor"><div class="profile-avatar">${avatarContent(state.user)}</div><div><h2>${esc(state.user.name)}</h2><p class="muted">${state.user.role==='admin'?'Administrador':'Técnico'}</p><div class="actions"><label class="btn btn-primary" for="profileAvatarInput">Adicionar avatar</label><input id="profileAvatarInput" type="file" accept="image/*" hidden>${state.user.avatar?'<button class="btn" data-action="remove-avatar">Remover avatar</button>':''}</div></div></div>${summary('Usuário',state.user.username)}${summary('Perfil',state.user.role==='admin'?'Administrador':'Técnico')}<h3 class="section-title">Biometria / Windows Hello</h3><p class="muted">Cadastre este dispositivo para entrar com impressão digital, reconhecimento facial ou PIN seguro.</p><div class="actions"><button class="btn btn-primary" data-action="register-biometric">◉ Cadastrar biometria</button><button class="btn" data-action="remove-biometric">Remover biometrias</button></div>${state.user.role==='admin'?`<h3 class="section-title">Backup do sistema</h3><p class="muted">O backup inclui usuários, veículos, fotos, clientes, ordens, estoque, financeiro, agenda e permissões.</p><div class="actions"><button class="btn btn-primary" data-action="download-backup">↓ Fazer backup</button><label class="btn" for="restoreBackupInput">↑ Restaurar backup</label><input id="restoreBackupInput" type="file" accept="application/json,.json" hidden></div>`:''}<button class="btn btn-danger" data-action="logout" style="margin-top:22px">Sair do sistema</button></section><section class="panel"><div class="panel-head"><h3>Atividades recentes</h3></div><div class="list">${audit.slice(0,12).map(a=>`<div class="list-row"><div><b>${esc(a.user)}</b> ${esc(a.action)}<div class="muted">${esc(a.target)}</div></div><small>${dt(a.at)}</small></div>`).join('')}</div></section></div>`}
function generic(view){const n=pageTitle();return`<div class="page-head"><div><h1>${n}</h1><p>Módulo integrado ao sistema</p></div><button class="btn btn-primary">＋ Novo registro</button></div>${genericPanel(n,'Nenhum registro cadastrado neste módulo.')}`}
function genericPanel(title,text){return`<section class="panel"><div class="panel-head"><h3>${title}</h3></div><div class="empty">${text}</div></section>`}
function more(){return`<div class="page-head"><div><h1>Mais opções</h1></div></div><div class="grid">${NAV.slice(4).map(n=>`<button class="nav-btn panel" data-go="${n[0]}"><span class="nav-icon">${n[1]}</span>${n[2]}</button>`).join('')}</div>`}

async function enhancedVehicleForm(){
  let v={active:true,photos:[]};if(state.params.id)v=await api('vehicles/'+state.params.id);state.vehiclePhotos=[...(v.photos||[])];
  return `<div class="page-head"><div><h1>${v.id?'Editar':'Cadastro de'} Veículo</h1><p>Preencha as informações do veículo</p></div><div class="actions"><button class="btn" data-go="vehicles">← Voltar</button><button class="btn btn-primary" data-action="save-vehicle">Salvar veículo</button></div></div><form id="vehicleForm" class="form-layout"><section class="panel form-main"><div class="tabs">${[['general','Dados Gerais'],['technical','Informações Técnicas'],['components','Componentes'],['notes','Observações'],['documents','Documentos']].map((t,i)=>`<button type="button" class="tab ${i===0?'active':''}" data-vehicle-tab="${t[0]}">${t[1]}</button>`).join('')}</div>
  <div class="vehicle-pane" data-vehicle-pane="general"><h3 class="section-title">Dados do Veículo</h3><div class="form-grid">${field('plate','Placa *',v.plate,true)}${field('renavam','Renavam',v.renavam)}${select('type','Tipo *',['Cavalo Mecânico','Caminhão Toco','Caminhão Truck','Ônibus','Van','Outro'],v.type)}${select('category','Categoria',['Particular','Frota','Terceiro'],v.category)}${field('brand','Marca *',v.brand,true)}${field('model','Modelo *',v.model,true)}${field('year','Ano Fabricação *',v.year,'number')}${field('modelYear','Ano Modelo',v.modelYear,'number')}${field('color','Cor',v.color)}${select('fuel','Combustível',['Diesel','Elétrico','Híbrido','Outro'],v.fuel)}${field('mileage','Quilometragem',v.mileage,'number')}${field('hours','Horímetro',v.hours,'number')}${field('chassis','Chassi (VIN) *',v.chassis,true)}${field('engine','Motor',v.engine)}${field('doors','Portas',v.doors,'number')}${select('traction','Capacidade de Tração',['4x2','6x2','6x4','8x2','8x4'],v.traction)}</div><h3 class="section-title">Informações do Proprietário</h3><div class="form-grid">${field('company','Cliente / Empresa *',v.company,true,'text','span-2')}${field('document','CNPJ / CPF',v.document)}${field('contact','Contato',v.contact)}${field('phone','Telefone',v.phone)}${field('email','E-mail',v.email,'email')}${field('city','Cidade',v.city)}${field('state','Estado',v.state)}</div></div>
  <div class="vehicle-pane hidden" data-vehicle-pane="technical"><h3 class="section-title">Informações Técnicas</h3><div class="form-grid">${field('enginePower','Potência do motor',v.enginePower)}${field('engineSerial','Número de série do motor',v.engineSerial)}${field('gearbox','Câmbio',v.gearbox)}${field('differential','Diferencial',v.differential)}${field('axles','Quantidade de eixos',v.axles,'number')}${field('weight','Peso bruto total (kg)',v.weight,'number')}${field('tireSize','Medida dos pneus',v.tireSize)}${field('battery','Especificação da bateria',v.battery)}</div></div>
  <div class="vehicle-pane hidden" data-vehicle-pane="components"><h3 class="section-title">Componentes instalados</h3><div class="form-grid">${field('alternator','Alternador',v.alternator)}${field('starter','Motor de partida',v.starter)}${field('turbo','Turbina',v.turbo)}${field('injection','Sistema de injeção',v.injection)}${field('brakes','Sistema de freios',v.brakes)}${field('suspension','Suspensão',v.suspension)}${field('airConditioning','Ar-condicionado',v.airConditioning)}${field('tachograph','Tacógrafo',v.tachograph)}</div></div>
  <div class="vehicle-pane hidden" data-vehicle-pane="notes"><h3 class="section-title">Observações</h3><div class="field"><label>Observações gerais sobre o veículo</label><textarea name="notes" rows="10">${esc(v.notes||'')}</textarea></div><label class="switch"><input type="checkbox" name="active" ${v.active!==false?'checked':''}> Veículo ativo — disponível para novas OS</label></div>
  <div class="vehicle-pane hidden" data-vehicle-pane="documents"><h3 class="section-title">Documentos</h3><div class="form-grid">${field('licenseExpiry','Vencimento do licenciamento',v.licenseExpiry,'date')}${field('insuranceExpiry','Vencimento do seguro',v.insuranceExpiry,'date')}<div class="field span-all"><label>Observações sobre documentos</label><textarea name="documentNotes" rows="5">${esc(v.documentNotes||'')}</textarea></div></div><div class="empty">O armazenamento de arquivos de documentos será disponibilizado em uma próxima etapa. Os dados acima já são salvos.</div></div>
  <input type="hidden" name="id" value="${esc(v.id||'')}"></section><aside class="side-stack"><section class="panel panel-pad"><h3>Fotos do Veículo</h3><div id="photoPreview">${photoPreview()}</div><label class="photo-add" style="margin-top:8px;aspect-ratio:auto;padding:13px">＋ Adicionar fotos<input id="photoInput" type="file" accept="image/*" multiple hidden></label><small class="muted">Até 8 imagens. O veículo permanecerá sem foto se nenhuma for adicionada.</small></section><section class="panel panel-pad"><h3>Resumo do Veículo</h3>${summary('Placa',v.plate)}${summary('Chassi',v.chassis)}${summary('Motor',v.engine)}${summary('Quilometragem',v.mileage?`${v.mileage} km`:'—')}</section></aside></form>`
}

async function clientsView(){const list=await api('clients');return `<div class="page-head"><div><h1>Clientes</h1><p>Clientes e empresas cadastrados</p></div><button class="btn btn-primary" data-action="new-client">＋ Novo cliente</button></div><section class="panel"><div class="panel-head"><h2>${list.length} cliente(s)</h2></div>${list.length?`<div class="table-wrap"><table><thead><tr><th>Nome / Empresa</th><th>CPF / CNPJ</th><th>Contato</th><th>Telefone</th><th>E-mail</th><th></th></tr></thead><tbody>${list.map(c=>`<tr><td><b>${esc(c.name)}</b></td><td>${esc(c.document||'—')}</td><td>${esc(c.contact||'—')}</td><td>${esc(c.phone||'—')}</td><td>${esc(c.email||'—')}</td><td><button class="btn" data-edit-client="${c.id}">Editar</button></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">Nenhum cliente cadastrado.</div>'}</section>`}
async function clientModal(id=''){const c=id?await api('clients/'+id):{};modal(`<div class="modal-title"><h2>${id?'Editar':'Novo'} cliente</h2><button type="button" class="close" data-action="close-modal">×</button></div><form id="clientForm"><input type="hidden" name="id" value="${esc(id)}">${field('name','Nome / Empresa *',c.name,true)}${field('document','CPF / CNPJ',c.document)}${field('contact','Contato',c.contact)}${field('phone','Telefone',c.phone)}${field('email','E-mail',c.email,'email')}${field('address','Endereço',c.address)}<button class="btn btn-primary btn-block">Salvar cliente</button></form>`)}

async function stockView(){const list=await api('stock');return `<div class="page-head"><div><h1>Estoque</h1><p>Peças e materiais da oficina</p></div><button class="btn btn-primary" data-action="new-stock">＋ Nova peça</button></div><section class="panel"><div class="panel-head"><h2>${list.length} item(ns)</h2></div>${list.length?`<div class="table-wrap"><table><thead><tr><th>Código</th><th>Descrição</th><th>Categoria</th><th>Quantidade</th><th>Mínimo</th><th>Valor unitário</th><th>Status</th><th></th></tr></thead><tbody>${list.map(i=>`<tr><td>${esc(i.code||'—')}</td><td><b>${esc(i.name)}</b></td><td>${esc(i.category||'—')}</td><td>${esc(i.quantity||0)}</td><td>${esc(i.minimum||0)}</td><td>${money(i.value)}</td><td>${Number(i.quantity)<=Number(i.minimum)?'<span class="status orange">Baixo</span>':'<span class="status green">OK</span>'}</td><td><button class="btn" data-edit-stock="${i.id}">Editar</button></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">Nenhum item cadastrado no estoque.</div>'}</section>`}
async function stockModal(id=''){const i=id?await api('stock/'+id):{};modal(`<div class="modal-title"><h2>${id?'Editar':'Novo'} item de estoque</h2><button type="button" class="close" data-action="close-modal">×</button></div><form id="stockForm"><input type="hidden" name="id" value="${esc(id)}">${field('name','Descrição *',i.name,true)}${field('code','Código',i.code)}${field('category','Categoria',i.category)}${field('brand','Marca',i.brand)}${field('quantity','Quantidade',i.quantity||0,'number')}${field('minimum','Estoque mínimo',i.minimum||0,'number')}${field('value','Valor unitário',i.value||0,'number')}<button class="btn btn-primary btn-block">Salvar item</button></form>`)}

async function financeView(){const [list,orders,vehicles]=await Promise.all([api('finance'),api('orders'),api('vehicles')]),income=list.filter(x=>x.type==='Receita').reduce((a,x)=>a+Number(x.value||0),0),expense=list.filter(x=>x.type==='Despesa').reduce((a,x)=>a+Number(x.value||0),0),receivables=orders.map(o=>{const total=(o.services||[]).reduce((a,x)=>a+Number(x.value||0),0)+(o.parts||[]).reduce((a,x)=>a+Number(x.qty||0)*Number(x.value||0),0),vehicle=vehicles.find(v=>v.id===o.vehicleId)||{},payment=paymentInfo(o.paymentTerms,o.createdAt);return{o,total,vehicle,payment}}).filter(x=>x.total>0&&x.o.paymentStatus!=='paid'),toReceive=receivables.reduce((a,x)=>a+x.total,0);return `<div class="page-head"><div><h1>Financeiro</h1><p>Receitas, despesas e valores a receber das ordens de serviço</p></div><button class="btn btn-primary" data-action="new-finance">＋ Novo lançamento</button></div><section class="grid stats" style="grid-template-columns:repeat(4,1fr)"><article class="stat"><div class="muted">Valores a receber</div><strong class="yellow">${money(toReceive)}</strong></article><article class="stat"><div class="muted">Receitas lançadas</div><strong class="green">${money(income)}</strong></article><article class="stat"><div class="muted">Despesas</div><strong style="color:var(--red)">${money(expense)}</strong></article><article class="stat"><div class="muted">Saldo lançado</div><strong>${money(income-expense)}</strong></article></section><section class="panel receivables-panel"><div class="panel-head"><h2>Valores a receber por prazo</h2><span class="muted">Dia 15 · Dia 30/último dia · pagamentos imediatos</span></div>${receivables.length?`<div class="table-wrap"><table><thead><tr><th>OS</th><th>Cliente / Veículo</th><th>Prazo / Forma</th><th>Vencimento</th><th>Valor a receber</th></tr></thead><tbody>${receivables.map(x=>`<tr data-open-os="${x.o.id}"><td><b>#${x.o.number}</b></td><td>${esc(x.vehicle.company||'—')}<div class="muted">${esc(x.vehicle.plate||'')} · ${esc(x.vehicle.brand||'')} ${esc(x.vehicle.model||'')}</div></td><td><span class="status ${x.o.paymentTerms==='dia-15'?'yellow':x.o.paymentTerms==='dia-30'?'orange':'green'}">${x.payment.label}</span></td><td>${x.payment.due}</td><td><b>${money(x.total)}</b></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">Nenhuma OS com valor pendente para receber.</div>'}</section><section class="panel" style="margin-top:14px"><div class="panel-head"><h2>Lançamentos manuais</h2></div>${list.length?`<div class="table-wrap"><table><thead><tr><th>Data</th><th>Descrição</th><th>Categoria</th><th>Tipo</th><th>Valor</th><th></th></tr></thead><tbody>${list.map(i=>`<tr><td>${date(i.date)}</td><td><b>${esc(i.description)}</b></td><td>${esc(i.category||'—')}</td><td>${i.type==='Receita'?'<span class="status green">Receita</span>':'<span class="status orange">Despesa</span>'}</td><td>${money(i.value)}</td><td><button class="btn" data-edit-finance="${i.id}">Editar</button></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">Nenhum lançamento financeiro.</div>'}</section>`}
async function financeModal(id=''){const i=id?await api('finance/'+id):{};modal(`<div class="modal-title"><h2>${id?'Editar':'Novo'} lançamento</h2><button type="button" class="close" data-action="close-modal">×</button></div><form id="financeForm"><input type="hidden" name="id" value="${esc(id)}">${field('description','Descrição *',i.description,true)}${select('type','Tipo',['Receita','Despesa'],i.type||'Receita')}${field('category','Categoria',i.category)}${field('date','Data',i.date||new Date().toISOString().slice(0,10),'date')}${field('value','Valor *',i.value||0,'number')}<button class="btn btn-primary btn-block">Salvar lançamento</button></form>`)}

async function saveVehicle(){const f=$('#vehicleForm');if(!f.reportValidity())return;const fd=new FormData(f),data=Object.fromEntries(fd.entries());data.active=f.elements.active.checked;data.photos=state.vehiclePhotos;const id=data.id;delete data.id;try{await api('vehicles'+(id?'/'+id:''),{method:id?'PUT':'POST',body:JSON.stringify(data)});toast('Veículo salvo com sucesso.');go('vehicles')}catch(e){toast(e.message)}}
async function resizeImages(files){for(const file of [...files].slice(0,8-state.vehiclePhotos.length)){if(!file.type.startsWith('image/'))continue;const data=await new Promise((resolve,reject)=>{const reader=new FileReader();reader.onerror=reject;reader.onload=()=>{const img=new Image();img.onload=()=>{const max=960,scale=Math.min(1,max/Math.max(img.width,img.height));const canvas=document.createElement('canvas');canvas.width=Math.round(img.width*scale);canvas.height=Math.round(img.height*scale);canvas.getContext('2d').drawImage(img,0,0,canvas.width,canvas.height);resolve(canvas.toDataURL('image/jpeg',.72))};img.src=reader.result};reader.readAsDataURL(file)});state.vehiclePhotos.push(data)}$('#photoPreview').innerHTML=photoPreview()}
async function saveProfileAvatar(file){if(!file?.type?.startsWith('image/'))return toast('Selecione uma imagem válida.');try{const avatar=await new Promise((resolve,reject)=>{const reader=new FileReader();reader.onerror=reject;reader.onload=()=>{const img=new Image();img.onerror=reject;img.onload=()=>{const size=Math.min(img.width,img.height),sx=(img.width-size)/2,sy=(img.height-size)/2,canvas=document.createElement('canvas');canvas.width=320;canvas.height=320;canvas.getContext('2d').drawImage(img,sx,sy,size,size,0,0,320,320);resolve(canvas.toDataURL('image/jpeg',.86))};img.src=reader.result};reader.readAsDataURL(file)}),result=await api('profile',{method:'PUT',body:JSON.stringify({avatar})});state.user=result.user;toast('Avatar atualizado.');render()}catch(e){toast(e.message||'Não foi possível salvar o avatar.')}}
async function removeProfileAvatar(){const result=await api('profile',{method:'PUT',body:JSON.stringify({avatar:''})});state.user=result.user;toast('Avatar removido.');render()}
async function updateOrder(patch){const o=await api('orders/'+state.params.id);Object.assign(o,patch);return api('orders/'+o.id,{method:'PUT',body:JSON.stringify(o)})}
function itemModal(type){const service=type==='service';modal(`<div class="modal-title"><h2>Adicionar ${service?'serviço':'peça'}</h2><button class="close" data-action="close-modal">×</button></div><form id="itemForm"><div class="field"><label>Descrição</label><input name="description" required></div>${service?'<div class="field"><label>Mecânico</label><input name="mechanic" required></div>':'<div class="field"><label>Quantidade</label><input name="qty" type="number" min="1" value="1" required></div>'}<div class="field"><label>Valor ${service?'':'unitário'}</label><input name="value" type="number" step="0.01" required></div><input type="hidden" name="type" value="${type}"><button class="btn btn-primary btn-block">Adicionar</button></form>`)}
async function finalizeOrderModal(){const o=await api('orders/'+state.params.id),total=(o.services||[]).reduce((sum,item)=>sum+Number(item.value||0),0)+(o.parts||[]).reduce((sum,item)=>sum+Number(item.qty||0)*Number(item.value||0),0),term=o.paymentTerms||'dia-15',scheduled=['dia-15','dia-30'].includes(term),due=paymentDueDate(term);modal(`<div class="modal-title"><div><h2>Recebimento da OS #${esc(o.number)}</h2><p class="muted">Confirme o pagamento para encerrar a ordem de serviço.</p></div><button class="close" data-action="close-modal">×</button></div><div class="receive-total"><span>Valor total da OS</span><strong>${money(total)}</strong></div><form id="finalizeOrderForm"><div class="form-grid"><div class="field"><label>Prazo / forma de pagamento</label><select name="paymentTerms" id="finalizePaymentTerms" required>${Object.entries(PAYMENT_LABELS).map(([value,label])=>`<option value="${value}" ${value===term?'selected':''}>${label}</option>`).join('')}</select></div><div class="field"><label>Situação do recebimento</label><select name="paymentStatus" id="finalizePaymentStatus" required><option value="pending" ${scheduled?'selected':''}>A receber</option><option value="paid" ${!scheduled?'selected':''}>Recebido agora</option></select></div><div class="field" id="finalizeDueField"><label>Data de vencimento</label><input name="dueDate" id="finalizeDueDate" type="date" value="${due}"></div><div class="field"><label>Valor</label><input name="receivedValue" type="number" min="0" step="0.01" value="${total.toFixed(2)}" required></div></div><div class="field"><label>Observação financeira</label><textarea name="financialNotes" placeholder="Opcional"></textarea></div><button class="btn btn-primary btn-block">Confirmar recebimento e finalizar OS</button></form>`)}
function shareModal(){const users=JSON.parse($('#usersData')?.textContent||'[]').filter(u=>u.id!==state.user.id);modal(`<div class="modal-title"><h2>Compartilhar informações</h2><button class="close" data-action="close-modal">×</button></div><form id="shareForm"><div class="field"><label>Usuário</label><select name="recipientId" required>${users.map(u=>`<option value="${u.id}">${esc(u.name)}</option>`).join('')}</select></div><div class="field"><label>Informações</label><select name="resource"><option value="vehicles">Veículos</option><option value="orders">Ordens de Serviço</option><option value="agenda">Agenda</option></select></div><div class="field"><label>Permissão</label><select name="permission"><option value="view">Somente visualizar</option><option value="edit">Visualizar e editar</option></select></div><button class="btn btn-primary btn-block">Enviar solicitação</button></form>`)}
async function orderShareModal(order){const users=(await api('users')).filter(u=>u.id!==state.user.id);modal(`<div class="modal-title"><h2>Compartilhar OS #${order.number}</h2><button class="close" data-action="close-modal">×</button></div><p class="muted">O usuário escolhido precisará aprovar a solicitação antes de acessar esta OS.</p><form id="orderShareForm"><div class="field"><label>Usuário</label><select name="recipientId" required>${users.map(u=>`<option value="${u.id}">${esc(u.name)}</option>`).join('')}</select></div><div class="field"><label>Permissão</label><select name="permission"><option value="view">Somente visualizar</option><option value="edit">Visualizar e editar</option></select></div><input type="hidden" name="resource" value="orders"><input type="hidden" name="resourceId" value="${order.id}"><button class="btn btn-primary btn-block">Enviar solicitação</button></form>`)}
async function enhanceOrderUI(){if(state.view!=='order-detail'||!state.params.id)return;try{const order=await api('orders/'+state.params.id),payment=paymentInfo(order.paymentTerms,order.createdAt);const head=$('.os-head-card');if(head&&!document.querySelector('[data-payment-card]'))head.insertAdjacentHTML('afterend',`<section class="panel payment-card" data-payment-card><div><span class="muted">PRAZO / FORMA DE PAGAMENTO</span><h3>${payment.label}</h3><small>${payment.detail}</small></div></section>`);const actions=$('.page-head .actions');if(actions&&order.ownerId===state.user.id&&!actions.querySelector('[data-action="share-order"]')){const button=document.createElement('button');button.type='button';button.className='btn';button.dataset.action='share-order';button.textContent='⇄ Compartilhar OS';button.onclick=()=>orderShareModal(order);actions.prepend(button)}}catch(e){console.warn(e)}}
function eventModal(){modal(`<div class="modal-title"><h2>Novo compromisso</h2><button class="close" data-action="close-modal">×</button></div><form id="eventForm"><div class="field"><label>Título</label><input name="title" required></div><div class="field"><label>Data e hora</label><input name="start" type="datetime-local" required></div><div class="field"><label>Descrição</label><textarea name="description"></textarea></div><button class="btn btn-primary btn-block">Salvar na agenda</button></form>`)}
async function saveResourceForm(form,resource){const data=Object.fromEntries(new FormData(form)),id=data.id;delete data.id;await api(resource+(id?'/'+id:''),{method:id?'PUT':'POST',body:JSON.stringify(data)});closeModal();toast('Registro salvo com sucesso.');render()}
const toB64url=data=>{const bytes=new Uint8Array(data);let s='';bytes.forEach(b=>s+=String.fromCharCode(b));return btoa(s).replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'')};
const fromB64url=s=>{s=s.replace(/-/g,'+').replace(/_/g,'/');while(s.length%4)s+='=';const raw=atob(s),bytes=new Uint8Array(raw.length);for(let i=0;i<raw.length;i++)bytes[i]=raw.charCodeAt(i);return bytes};
function biometricSupported(){return !!(window.PublicKeyCredential&&navigator.credentials&&window.isSecureContext)}
async function registerBiometric(){if(!biometricSupported())return toast('Este navegador ou dispositivo não oferece biometria compatível.');try{const o=await api('biometric/register-options',{method:'POST',body:'{}'});const credential=await navigator.credentials.create({publicKey:{challenge:fromB64url(o.challenge),rp:o.rp,user:{id:fromB64url(o.user.id),name:o.user.name,displayName:o.user.displayName},pubKeyCredParams:[{type:'public-key',alg:-7},{type:'public-key',alg:-257}],authenticatorSelection:{authenticatorAttachment:'platform',residentKey:'preferred',userVerification:'required'},timeout:60000,attestation:'none'}});const publicKey=credential.response.getPublicKey?.();if(!publicKey)throw new Error('Chave pública indisponível');await api('biometric/register-complete',{method:'POST',body:JSON.stringify({credentialId:toB64url(credential.rawId),publicKey:toB64url(publicKey),clientDataJSON:toB64url(credential.response.clientDataJSON),name:navigator.userAgentData?.platform||navigator.platform||'Dispositivo'})});toast('Biometria cadastrada com sucesso.')}catch(e){if(e.name==='NotAllowedError')toast('Cadastro biométrico cancelado.');else toast(e.message||'Não foi possível cadastrar a biometria.')}}
async function biometricLogin(){if(!biometricSupported())return toast('Biometria indisponível neste dispositivo.');const username=$('#loginForm input[name="username"]')?.value.trim();if(!username)return toast('Informe o usuário antes de usar a biometria.');try{const o=await api('biometric/login-options',{method:'POST',body:JSON.stringify({username})});const credential=await navigator.credentials.get({publicKey:{challenge:fromB64url(o.challenge),rpId:o.rpId,allowCredentials:o.allowCredentials.map(c=>({type:'public-key',id:fromB64url(c.id)})),userVerification:'required',timeout:60000}});const r=credential.response,result=await api('biometric/login-complete',{method:'POST',body:JSON.stringify({userId:o.userId,credentialId:toB64url(credential.rawId),clientDataJSON:toB64url(r.clientDataJSON),authenticatorData:toB64url(r.authenticatorData),signature:toB64url(r.signature)})});state.token=result.token;state.user=result.user;localStorage.setItem('gl_token',result.token);state.view='dashboard';render()}catch(e){if(e.name==='NotAllowedError')toast('Autenticação biométrica cancelada.');else toast(e.message||'Não foi possível entrar com biometria.')}}
async function downloadBackup(){try{const backup=await api('backup'),blob=new Blob([JSON.stringify(backup,null,2)],{type:'application/json'}),url=URL.createObjectURL(blob),link=document.createElement('a');link.href=url;link.download=`NA-Diesel-backup-${new Date().toISOString().slice(0,10)}.json`;document.body.appendChild(link);link.click();link.remove();URL.revokeObjectURL(url);toast('Backup gerado com sucesso.')}catch(e){toast(e.message)}}
async function restoreBackup(file){if(!file)return;try{const text=await file.text(),backup=JSON.parse(text);if(!confirm('Restaurar este backup substituirá todos os dados atuais. Deseja continuar?'))return;const result=await api('backup',{method:'POST',body:JSON.stringify(backup)});toast(result.message||'Backup restaurado.');setTimeout(()=>location.reload(),900)}catch(e){toast(e.message||'Não foi possível restaurar o backup.')}}
function installApp(){if(deferredInstallPrompt){deferredInstallPrompt.prompt();deferredInstallPrompt.userChoice.finally(()=>{deferredInstallPrompt=null;document.documentElement.classList.remove('can-install')});return}const ios=/iphone|ipad|ipod/i.test(navigator.userAgent);toast(ios?'No Safari, toque em Compartilhar e depois em “Adicionar à Tela de Início”.':'Abra o menu do navegador e escolha “Instalar aplicativo”.')}
function enhanceInstallUI(){if(matchMedia('(display-mode: standalone)').matches||document.querySelector('[data-action="install-app"]'))return;const biometric=document.querySelector('.biometric-btn');if(biometric){const button=document.createElement('button');button.type='button';button.className='btn btn-block install-btn';button.dataset.action='install-app';button.innerHTML='↓ Instalar N.A.Diesel neste dispositivo';biometric.insertAdjacentElement('afterend',button)}}

function bind(){
  const brandLogo=$('.brand img');if(brandLogo)brandLogo.src='/images/logo.png';$$('.avatar').forEach(el=>el.innerHTML=avatarContent(state.user));enhanceOrderUI();enhanceInstallUI();
  const login=$('#loginForm');if(login)login.onsubmit=async e=>{e.preventDefault();const d=Object.fromEntries(new FormData(login));try{const r=await api('login',{method:'POST',body:JSON.stringify(d)});state.token=r.token;state.user=r.user;localStorage.setItem('gl_token',r.token);state.view='dashboard';render()}catch(err){toast(err.message)}};
  $('[data-action="biometric-login"]')?.addEventListener('click',biometricLogin);$('[data-action="register-biometric"]')?.addEventListener('click',registerBiometric);$('[data-action="remove-biometric"]')?.addEventListener('click',async()=>{if(confirm('Remover todas as biometrias cadastradas para este usuário?')){await api('biometric',{method:'DELETE'});toast('Biometrias removidas.')}});
  $('[data-action="install-app"]')?.addEventListener('click',installApp);
  $('[data-action="download-backup"]')?.addEventListener('click',downloadBackup);$('#restoreBackupInput')?.addEventListener('change',e=>restoreBackup(e.target.files?.[0]));
  $('#profileAvatarInput')?.addEventListener('change',e=>saveProfileAvatar(e.target.files?.[0]));$('[data-action="remove-avatar"]')?.addEventListener('click',removeProfileAvatar);
  $$('[data-go]').forEach(el=>el.onclick=()=>go(el.dataset.go));
  $$('[data-open-vehicle]').forEach(el=>el.onclick=()=>go('vehicle-form',{id:el.dataset.openVehicle}));
  $$('[data-open-os]').forEach(el=>el.onclick=()=>go('order-detail',{id:el.dataset.openOs}));
  $$('[data-os-tab]').forEach(el=>el.onclick=()=>go('order-detail',{id:state.params.id,tab:el.dataset.osTab}));
  $$('[data-check-cat]').forEach(el=>el.onclick=()=>go('order-detail',{id:state.params.id,tab:'checklist',category:el.dataset.checkCat}));
  $$('[data-check-key]').forEach(el=>el.onclick=async()=>{const o=await api('orders/'+state.params.id);o.checklist=o.checklist||{};const k=el.dataset.checkKey,s=el.dataset.state;o.checklist[k]={state:o.checklist[k]?.state===s?'':s,at:new Date().toISOString(),user:state.user.name};await api('orders/'+o.id,{method:'PUT',body:JSON.stringify(o)});render()});
  const vf=$('#vehicleForm');$('[data-action="save-vehicle"]')?.addEventListener('click',saveVehicle);$('#photoInput')?.addEventListener('change',e=>resizeImages(e.target.files));$$('[data-remove-photo]').forEach(b=>b.onclick=()=>{state.vehiclePhotos.splice(Number(b.dataset.removePhoto),1);$('#photoPreview').innerHTML=photoPreview();bind()});$$('[data-vehicle-tab]').forEach(tab=>tab.onclick=()=>{$$('[data-vehicle-tab]').forEach(x=>x.classList.toggle('active',x===tab));$$('[data-vehicle-pane]').forEach(p=>p.classList.toggle('hidden',p.dataset.vehiclePane!==tab.dataset.vehicleTab))});
  $('#orderForm')?.addEventListener('submit',async e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.target));try{const o=await api('orders',{method:'POST',body:JSON.stringify(d)});toast(`OS #${o.number} aberta.`);go('order-detail',{id:o.id})}catch(err){toast(err.message)}});
  $('[data-action="add-service"]')?.addEventListener('click',()=>itemModal('service'));$('[data-action="add-part"]')?.addEventListener('click',()=>itemModal('part'));
  $('#itemForm')?.addEventListener('submit',async e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.target)),o=await api('orders/'+state.params.id);if(d.type==='service')o.services.push({description:d.description,mechanic:d.mechanic,value:Number(d.value)});else o.parts.push({description:d.description,qty:Number(d.qty),value:Number(d.value)});await api('orders/'+o.id,{method:'PUT',body:JSON.stringify(o)});closeModal();render()});
  $$('[data-remove-item]').forEach(b=>b.onclick=async()=>{const [type,i]=b.dataset.removeItem.split(':'),o=await api('orders/'+state.params.id);o[type==='service'?'services':'parts'].splice(Number(i),1);await api('orders/'+o.id,{method:'PUT',body:JSON.stringify(o)});render()});
  $('[data-action="save-diagnosis"]')?.addEventListener('click',async()=>{await updateOrder({diagnosis:$('#diagnosisText').value});toast('Diagnóstico salvo.')});
  $('[data-action="finalize-os"]')?.addEventListener('click',finalizeOrderModal);
  const paymentTerms=$('#finalizePaymentTerms'),paymentStatus=$('#finalizePaymentStatus'),dueDate=$('#finalizeDueDate'),dueField=$('#finalizeDueField');const syncFinalizePayment=()=>{if(!paymentTerms)return;const scheduled=['dia-15','dia-30'].includes(paymentTerms.value);if(dueField)dueField.classList.toggle('hidden',!scheduled);if(dueDate){dueDate.required=scheduled;if(scheduled)dueDate.value=paymentDueDate(paymentTerms.value);else dueDate.value=''}if(paymentStatus)paymentStatus.value=scheduled?'pending':'paid'};paymentTerms?.addEventListener('change',syncFinalizePayment);
  $('#finalizeOrderForm')?.addEventListener('submit',async e=>{e.preventDefault();const data=Object.fromEntries(new FormData(e.target));try{await api('orders/'+state.params.id+'/close',{method:'POST',body:JSON.stringify(data)});closeModal();toast(data.paymentStatus==='paid'?'OS finalizada e recebimento registrado.':'OS finalizada e valor agendado no financeiro.');render()}catch(err){toast(err.message)}});
  $('[data-action="new-share"]')?.addEventListener('click',shareModal);$('#shareForm')?.addEventListener('submit',async e=>{e.preventDefault();await api('shares',{method:'POST',body:JSON.stringify(Object.fromEntries(new FormData(e.target)))});closeModal();toast('Solicitação enviada.');render()});
  $('#orderShareForm')?.addEventListener('submit',async e=>{e.preventDefault();await api('shares',{method:'POST',body:JSON.stringify(Object.fromEntries(new FormData(e.target)))});closeModal();toast('Solicitação de acesso à OS enviada.');render()});
  $$('[data-share-response]').forEach(b=>b.onclick=async()=>{const [id,status]=b.dataset.shareResponse.split(':');await api('shares/'+id,{method:'PUT',body:JSON.stringify({status})});render()});$$('[data-revoke-share]').forEach(b=>b.onclick=async()=>{await api('shares/'+b.dataset.revokeShare,{method:'DELETE'});render()});
  $('[data-action="new-event"]')?.addEventListener('click',eventModal);$('#eventForm')?.addEventListener('submit',async e=>{e.preventDefault();await api('agenda',{method:'POST',body:JSON.stringify(Object.fromEntries(new FormData(e.target)))});closeModal();render()});
  $('[data-action="new-client"]')?.addEventListener('click',()=>clientModal());$$('[data-edit-client]').forEach(b=>b.onclick=()=>clientModal(b.dataset.editClient));$('#clientForm')?.addEventListener('submit',async e=>{e.preventDefault();await saveResourceForm(e.target,'clients')});
  $('[data-action="new-stock"]')?.addEventListener('click',()=>stockModal());$$('[data-edit-stock]').forEach(b=>b.onclick=()=>stockModal(b.dataset.editStock));$('#stockForm')?.addEventListener('submit',async e=>{e.preventDefault();await saveResourceForm(e.target,'stock')});
  $('[data-action="new-finance"]')?.addEventListener('click',()=>financeModal());$$('[data-edit-finance]').forEach(b=>b.onclick=()=>financeModal(b.dataset.editFinance));$('#financeForm')?.addEventListener('submit',async e=>{e.preventDefault();await saveResourceForm(e.target,'finance')});
  $$('[data-action="close-modal"]').forEach(b=>b.onclick=closeModal);$('[data-action="menu"]')?.addEventListener('click',()=>{state.menu=!state.menu;$('.shell')?.classList.toggle('menu-open',state.menu)});$$('[data-action="logout"]').forEach(b=>b.onclick=()=>logout());
  $('[data-action="quick"]')?.addEventListener('click',()=>go('order-new'));
  $('#globalSearch')?.addEventListener('keydown',async e=>{if(e.key!=='Enter')return;const q=e.target.value.toLowerCase(),vs=await api('vehicles'),v=vs.find(x=>[x.plate,x.brand,x.model,x.chassis].some(y=>String(y||'').toLowerCase().includes(q)));if(v)go('vehicle-form',{id:v.id});else{const os=await api('orders'),o=os.find(x=>String(x.number).includes(q));o?go('order-detail',{id:o.id}):toast('Nenhum resultado encontrado.')}});
}
async function logout(call=true){if(call&&state.token)api('logout',{method:'POST'}).catch(()=>{});state.token='';state.user=null;localStorage.removeItem('gl_token');render()}
async function init(){if(state.token){try{state.user=(await api('me')).user}catch{state.token='';localStorage.removeItem('gl_token')}}const hash=location.hash.slice(1).split('/');if(hash[0]){state.view=hash[0];if(hash[1])state.params.id=hash[1]}render();if('serviceWorker'in navigator)navigator.serviceWorker.register('/sw.js').catch(()=>{})}
window.addEventListener('popstate',e=>{if(e.state){state.view=e.state.view;state.params=e.state.params||{};render()}});$('#modal')?.addEventListener('click',e=>{if(e.target.id==='modal')closeModal()});init();
